import React from 'react';
import { useWebSocket } from '../hooks/useWebSocket';
import { DotMatrixGauge } from './NothingGauges';
import { motion } from 'framer-motion';

const DashboardOverview = () => {
    const { data } = useWebSocket("ws://localhost:8000/ws");

    if (!data) return (
        <div className="space-y-8 animate-pulse">
            <div className="h-12 bg-white/5 rounded-lg" />
            <div className="h-12 bg-white/5 rounded-lg" />
            <div className="h-12 bg-white/5 rounded-lg" />
        </div>
    );

    return (
        <div className="space-y-8">
            <DotMatrixGauge
                label="AGENT_OCCUPANCY"
                value={Math.round((data.current_metrics.active_agents / 5) * 100)}
                sublabel={`${data.current_metrics.active_agents} / 5 AGENTS ACTIVE`}
            />

            <DotMatrixGauge
                label="SYSTEM_DB_LOAD"
                value={data.current_metrics.db_load}
                sublabel="REAL-TIME THROUGHPUT OPTIMIZATION"
                color={data.current_metrics.db_load > 80 ? '#FF3B30' : '#FFFFFF'}
            />

            <div className="pt-4 border-t border-white/5">
                <div className="flex justify-between items-end mb-1">
                    <span className="nothing-text-label text-white/60">COST_EFFICIENCY</span>
                    <span className="text-white font-mono text-2xl font-black italic">
                        +${data.current_metrics.cost_savings_usd.toLocaleString()}
                    </span>
                </div>
                <div className="flex items-center space-x-2">
                    <div className="flex-grow bg-white/5 h-[1px]">
                        <motion.div
                            className="bg-white h-full shadow-[0_0_10px_white]"
                            initial={{ width: 0 }}
                            animate={{ width: '82%' }}
                            transition={{ duration: 2 }}
                        />
                    </div>
                    <span className="text-[8px] text-white/20 font-mono italic">USD_SAVED</span>
                </div>
            </div>
        </div>
    );
};

export default DashboardOverview;
